import brandingBg from '../assets/branding_bg.jpg';

const Login = () => {
  // ... states ...
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setError('');
      setLoading(true);
      await login(email, password);
      navigate('/');
    } catch (err) {
      setError('Failed to log in. Please check your credentials.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-container" style={{
      backgroundImage: `linear-gradient(rgba(0,0,0,0.3), rgba(0,0,0,0.3)), url(${brandingBg})`,
      backgroundSize: 'cover',
      backgroundPosition: 'center'
    }}>
      <div className="login-card">
        <div className="login-header">
          <div className="login-logo">🏍️</div>
          <h1>BikesZone Admin</h1>
          <p>Sign in to manage your marketplace</p>
        </div>

        {error && <div className="login-error">{error}</div>}

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label className="form-label">Email Address</label>
            <input
              className="form-input"
              type="email"
              placeholder="admin@bikeszone.com"
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label className="form-label">Password</label>
            <input
              className="form-input"
              type="password"
              placeholder="••••••••"
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          <button
            type="submit"
            className="btn btn-primary btn-lg"
            disabled={loading}
            style={{ width: '100%', marginTop: '1rem' }}
          >
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>

        <div className="login-footer">
          <p>Don't have an account? Contact your distributor.</p>
        </div>
      </div>

      <div className="login-brand-footer">
        <p>BikesZone</p>
      </div>

      <style jsx="true">{`
        .login-container {
          display: flex;
          align-items: center;
          justify-content: center;
          min-height: 100vh;
          padding: 2rem;
          position: relative;
        }
        .login-card {
          width: 100%;
          max-width: 420px;
          background: rgba(255, 255, 255, 0.95);
          backdrop-filter: blur(10px);
          border: 1px solid rgba(255, 255, 255, 0.2);
          border-radius: var(--radius-lg);
          padding: 3rem 2.5rem;
          box-shadow: 0 20px 50px rgba(0,0,0,0.3);
          z-index: 2;
        }
        .login-brand-footer {
          position: absolute;
          bottom: 0;
          left: 0;
          right: 0;
          background: rgba(0, 0, 0, 0.85);
          padding: 1rem;
          text-align: center;
          z-index: 3;
        }
        .login-brand-footer p {
          color: #fff;
          margin: 0;
          font-family: 'Outfit', sans-serif;
          font-weight: 800;
          text-transform: uppercase;
          letter-spacing: 0.3em;
          font-size: 1.25rem;
        }
        .login-header {
          text-align: center;
          margin-bottom: 2.5rem;
        }
        .login-logo {
          font-size: 3rem;
          margin-bottom: 1rem;
        }
        .login-header h1 {
          font-size: 1.75rem;
          font-weight: 800;
          color: #0f172a;
          margin-bottom: 0.5rem;
        }
        .login-header p {
          color: #475569;
          font-size: 0.9rem;
        }
        .login-error {
          background: rgba(239, 68, 68, 0.1);
          color: #ef4444;
          padding: 0.75rem;
          border-radius: var(--radius-sm);
          font-size: 0.85rem;
          margin-bottom: 1.5rem;
          text-align: center;
          border: 1px solid rgba(239, 68, 68, 0.2);
        }
        .login-footer {
          margin-top: 2rem;
          text-align: center;
          border-top: 1px solid rgba(0,0,0,0.05);
          padding-top: 1.5rem;
        }
        .login-footer p {
          color: #64748b;
          font-size: 0.8rem;
        }
        .form-label {
          color: #0f172a !important;
          font-weight: 600;
        }
        .form-input {
          background: #fff;
          border: 1px solid #e2e8f0;
          color: #0f172a;
        }
      `}</style>
    </div>
  );
};

export default Login;
